#!/bin/bash

# Définition d'un programme pour simuler un événement d'interruption
interruption() {
  echo "Événement d'interruption détecté"
}

# Exécution du programme avec une interruption
echo "Travail en cours..."
interruption
echo "Continuation de l'exécution"

# Définition d'une fonction pour gérer les interruptions
gère_interruption() {
  case $1 in
    INT) echo "Événement d'interruption détecté ; rentrant dans le pipeline principal" ;;
    NOK) echo "Réponse rejetée, relancer l'exécution" ;;
  esac
}

# Gestion des interruptions avec la fonction définitive
gères_interruption INT
